import React from "react";

const Navbar = () => {

  const handleScroll = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav className="fixed w-full top-0 left-0 bg-white shadow-md z-50">
      <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
        {/* Name/Logo */}
        <div className="text-2xl font-bold text-gray-800 cursor-pointer" onClick={() => handleScroll('home')}>
          Sindhuja Kannuri
        </div>

        {/* Menu Items */}
        <ul className="flex space-x-8 text-gray-700 font-medium">
          <li>
            <button className="hover:text-blue-600" onClick={() => handleScroll('about')}>
              About
            </button>
          </li>
          <li>
            <button className="hover:text-blue-600" onClick={() => handleScroll('experience')}>
              Experience
            </button>
          </li>
          <li>
            <button className="hover:text-blue-600" onClick={() => handleScroll('projects')}>
              Projects
            </button>
          </li>
          <li>
            <button className="hover:text-blue-600" onClick={() => handleScroll('contact')}>
              Contact
            </button>
          </li>
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
